import { useState } from "react";
 
const IMG = "data:image/jpeg;base64,";
 
export default function LoginPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
 
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !password) return;
    setLoading(true);
    setTimeout(() => { setLoading(false); setSuccess(true); }, 1200);
  };
 
  return (
    <div style={{ minHeight: "100vh", display: "flex", background: "#f3f4f6", fontFamily: "sans-serif" }}>
      
      {/* ===== LEFT — الصورة ===== */}
      <div style={{
        flex: "0 0 48%",
        position: "relative",
        overflow: "hidden",
        display: "flex",
        alignItems: "stretch",
      }}>
        <img
          src={IMG}
          alt="background"
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
            objectPosition: "center",
            display: "block",
          }}
        />
        {/* طبقة شفافة فوق الصورة */}
        <div style={{
          position: "absolute", inset: 0,
          background: "rgba(0,40,10,0.38)",
          display: "flex", flexDirection: "column",
          justifyContent: "flex-end",
          padding: "2.5rem",
        }}>
          <div style={{
            width: 44, height: 44, borderRadius: 12,
            background: "rgba(74,188,100,0.85)",
            display: "flex", alignItems: "center", justifyContent: "center",
            marginBottom: "1rem",
          }}>
            <svg width="22" height="22" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
              <circle cx="9" cy="7" r="4"/>
              <path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>
            </svg>
          </div>
          <h2 style={{ color: "#fff", fontWeight: 700, fontSize: 26, margin: "0 0 8px" }}>
            HR Management System
          </h2>
          <p style={{ color: "rgba(255,255,255,0.75)", fontSize: 14, lineHeight: 1.6, margin: 0, maxWidth: 280 }}>
            Manage your workforce, training programs, and organizational resources — all in one place.
          </p>
          <div style={{ display: "flex", gap: 8, marginTop: "1.2rem" }}>
            {["Employees", "Training", "Analytics"].map(t => (
              <span key={t} style={{
                fontSize: 12, padding: "4px 12px", borderRadius: 20,
                border: "1px solid rgba(255,255,255,0.4)",
                color: "rgba(255,255,255,0.85)", background: "rgba(255,255,255,0.1)",
              }}>{t}</span>
            ))}
          </div>
        </div>
      </div>
 
      {/* ===== RIGHT — فورم تسجيل الدخول ===== */}
      <div style={{
        flex: 1,
        display: "flex", alignItems: "center", justifyContent: "center",
        padding: "2rem",
      }}>
        <div style={{
          width: "100%", maxWidth: 400,
          background: "#fff",
          border: "2px solid #2d7a3a",
          borderRadius: 18,
          padding: "2.2rem 2rem",
          boxSizing: "border-box",
        }}>
          {success ? (
            <div style={{ textAlign: "center", padding: "2rem 0" }}>
              <div style={{
                width: 60, height: 60, borderRadius: "50%",
                background: "#eaf3de",
                display: "flex", alignItems: "center", justifyContent: "center",
                margin: "0 auto 1rem",
              }}>
                <svg width="28" height="28" fill="none" stroke="#2d7a3a" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
                  <polyline points="20 6 9 17 4 12"/>
                </svg>
              </div>
              <p style={{ fontWeight: 600, fontSize: 16, color: "#27500a", margin: "0 0 6px" }}>تم تسجيل الدخول بنجاح</p>
              <p style={{ fontSize: 13, color: "#888", margin: 0 }}>جاري التحويل إلى لوحة التحكم…</p>
            </div>
          ) : (
            <>
              <div style={{ marginBottom: "1.6rem" }}>
                <h1 style={{ fontSize: 22, fontWeight: 700, color: "#111", margin: "0 0 4px" }}>مرحباً بعودتك</h1>
                <p style={{ fontSize: 13, color: "#888", margin: 0 }}>سجّل الدخول إلى حسابك في HRMS</p>
              </div>
 
              <form onSubmit={handleSubmit}>
                {/* Email */}
                <div style={{ marginBottom: "1rem" }}>
                  <label style={{ display: "block", fontSize: 12, fontWeight: 600, color: "#555", marginBottom: 6 }}>
                    البريد الإلكتروني
                  </label>
                  <div style={{ position: "relative" }}>
                    <svg style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", pointerEvents: "none" }}
                      width="16" height="16" fill="none" stroke="#aaa" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
                      <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/>
                    </svg>
                    <input
                      type="email" value={email} onChange={e => setEmail(e.target.value)}
                      placeholder="you@company.com" required
                      style={{
                        width: "100%", boxSizing: "border-box",
                        padding: "9px 12px 9px 34px", fontSize: 13,
                        border: "1px solid #ddd", borderRadius: 10,
                        background: "#f9fafb", color: "#111", outline: "none",
                        transition: "border-color .15s",
                      }}
                      onFocus={e => e.target.style.borderColor = "#2d7a3a"}
                      onBlur={e => e.target.style.borderColor = "#ddd"}
                    />
                  </div>
                </div>
 
                {/* Password */}
                <div style={{ marginBottom: "1rem" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                    <label style={{ fontSize: 12, fontWeight: 600, color: "#555" }}>كلمة المرور</label>
                    <button type="button" style={{ fontSize: 12, color: "#2d7a3a", background: "none", border: "none", cursor: "pointer", padding: 0 }}>
                      نسيت كلمة المرور؟
                    </button>
                  </div>
                  <div style={{ position: "relative" }}>
                    <svg style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", pointerEvents: "none" }}
                      width="16" height="16" fill="none" stroke="#aaa" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
                      <rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0 1 10 0v4"/>
                    </svg>
                    <input
                      type={showPass ? "text" : "password"} value={password}
                      onChange={e => setPassword(e.target.value)}
                      placeholder="••••••••" required
                      style={{
                        width: "100%", boxSizing: "border-box",
                        padding: "9px 36px 9px 34px", fontSize: 13,
                        border: "1px solid #ddd", borderRadius: 10,
                        background: "#f9fafb", color: "#111", outline: "none",
                        transition: "border-color .15s",
                      }}
                      onFocus={e => e.target.style.borderColor = "#2d7a3a"}
                      onBlur={e => e.target.style.borderColor = "#ddd"}
                    />
                    <button
                      type="button" onClick={() => setShowPass(!showPass)}
                      style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "#aaa", padding: 0 }}
                    >
                      {showPass ? (
                        <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
                          <path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24M1 1l22 22"/>
                        </svg>
                      ) : (
                        <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
                          <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>
                        </svg>
                      )}
                    </button>
                  </div>
                </div>
 
                {/* Remember me */}
                <label style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 12, color: "#666", marginBottom: "1.2rem", cursor: "pointer" }}>
                  <input type="checkbox" style={{ accentColor: "#2d7a3a", width: 15, height: 15 }} />
                  ابق متصلاً
                </label>
 
                {/* Submit */}
                <button
                  type="submit" disabled={loading}
                  style={{
                    width: "100%", padding: "10px", borderRadius: 10,
                    background: loading ? "#5a9e68" : "#2d7a3a",
                    color: "#fff", border: "none", fontSize: 14,
                    fontWeight: 600, cursor: loading ? "not-allowed" : "pointer",
                    display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
                    transition: "background .15s",
                  }}
                  onMouseEnter={e => { if (!loading) e.currentTarget.style.background = "#27500a"; }}
                  onMouseLeave={e => { if (!loading) e.currentTarget.style.background = "#2d7a3a"; }}
                >
                  {loading ? "جاري الدخول…" : "تسجيل الدخول"}
                </button>
              </form>
 
              <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "1.2rem 0" }}>
                <div style={{ flex: 1, height: 1, background: "#eee" }} />
                <span style={{ fontSize: 11, color: "#aaa" }}>أو</span>
                <div style={{ flex: 1, height: 1, background: "#eee" }} />
              </div>
 
              <button style={{
                width: "100%", padding: "9px", borderRadius: 10,
                border: "1px solid #e0e0e0", background: "#fff",
                fontSize: 13, color: "#444", cursor: "pointer",
                display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
              }}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <rect x="2" y="2" width="9" height="9" rx="1" fill="#4285F4"/>
                  <rect x="13" y="2" width="9" height="9" rx="1" fill="#34A853"/>
                  <rect x="2" y="13" width="9" height="9" rx="1" fill="#FBBC05"/>
                  <rect x="13" y="13" width="9" height="9" rx="1" fill="#EA4335"/>
                </svg>
                الدخول عبر Google SSO
              </button>
 
              <p style={{ textAlign: "center", fontSize: 12, color: "#999", marginTop: "1.2rem" }}>
                لا تملك حساباً؟{" "}
                <button style={{ color: "#2d7a3a", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 600, padding: 0 }}>
                  تواصل مع المشرف
                </button>
              </p>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
